/// Wrong iters should fail verification.
#[test]
fn test_wrong_iters_fails() {
    let d = get_discriminant();
    let x_s = hex_decode(X_S_HEX);
    let proof_blob = hex_decode(PROOF_BLOB_HEX);

    let result = check_proof_of_time_n_wesolowski(&d, &x_s, &proof_blob, ITERS + 1, 0);
    assert!(!result, "wrong iters should fail verification");
}

/// Wrong proof blob size should fail.
#[test]
fn test_wrong_blob_size_fails() {
    let d = get_discriminant();
    let x_s = hex_decode(X_S_HEX);
    let proof_blob = hex_decode(PROOF_BLOB_HEX);

    let result = check_proof_of_time_n_wesolowski(&d, &x_s, &proof_blob[..100], ITERS, 0);
    assert!(!result, "truncated blob should fail");

    let mut bad_blob = proof_blob.clone();
    bad_blob.push(0);
    let result = check_proof_of_time_n_wesolowski(&d, &x_s, &bad_blob, ITERS, 0);
    assert!(!result, "extended blob should fail");
}

/// Corrupted y bytes should fail verification.
#[test]
fn test_corrupted_y_fails() {
    let d = get_discriminant();
    let x_s = hex_decode(X_S_HEX);
    let mut proof_blob = hex_decode(PROOF_BLOB_HEX);

    proof_blob[5] ^= 0x01;
    let result = check_proof_of_time_n_wesolowski(&d, &x_s, &proof_blob, ITERS, 0);
    assert!(!result, "corrupted y should fail verification");
}

/// Flipping a padding byte of the y form triggers the BQFC canonical round-trip
/// check and is rejected by the Rust verifier.
///
/// For a 512-bit discriminant the active BQFC region is 52 bytes
/// (2 header + 32 a + 16 t + 1 g + 1 b0); bytes 52–99 must be zero.
/// The Rust deserializer re-serializes the decoded form and checks it matches
/// the input byte-for-byte — any deviation is rejected as non-canonical.
///
/// chiavdf's C++ decoder does not perform this round-trip check and ignores
/// bytes beyond the active region.  This is the discrepancy found by
/// differential fuzzing (scripts/differential_fuzz.py).
#[test]
fn test_non_canonical_y_padding_rejected() {
    let d = get_discriminant();
    let x_s = hex_decode(X_S_HEX);
    let mut proof_blob = hex_decode(PROOF_BLOB_HEX);

    // Byte 52 is the first zero-padding byte of the y form.
    proof_blob[52] ^= 0x01;
    assert!(
        !check_proof_of_time_n_wesolowski(&d, &x_s, &proof_blob, ITERS, 0),
        "non-zero y-form padding should fail the canonical round-trip check"
    );
}

/// IS_1 and IS_GEN forms use only byte 0; bytes 1–99 are don't-cares and are
/// silently ignored by the deserializer (early return before canonical check).
///
/// In this test vector the pi (witness) form is the identity (IS_1, byte 0 =
/// 0x04), so any mutation to its trailing bytes still decodes to (a=1, b=1)
/// and verification passes unchanged.  The same applies to x (IS_GEN, 0x08).
///
/// This is the complementary case to test_non_canonical_y_padding_rejected:
/// the canonical check only fires for ordinary (non-special) forms.
#[test]
fn test_is1_isgen_trailing_bytes_ignored() {
    let d = get_discriminant();
    let mut x_s = hex_decode(X_S_HEX);       // IS_GEN (0x08): bytes 1-99 ignored
    let mut proof_blob = hex_decode(PROOF_BLOB_HEX); // pi form is IS_1 (0x04): bytes 101-199 ignored

    x_s[99] ^= 0xff;
    proof_blob[199] ^= 0xff; // last byte of IS_1 pi form
    assert!(
        check_proof_of_time_n_wesolowski(&d, &x_s, &proof_blob, ITERS, 0),
        "trailing bytes of IS_GEN/IS_1 forms are don't-cares; proof should still verify"
    );
}

/// Corrupted proof bytes should fail verification.
#[test]
fn test_corrupted_proof_fails() {
    let d = get_discriminant();
    let x_s = hex_decode(X_S_HEX);
    let mut proof_blob = hex_decode(PROOF_BLOB_HEX);

    proof_blob[BQFC_FORM_SIZE] = 0x00;
    let result = check_proof_of_time_n_wesolowski(&d, &x_s, &proof_blob, ITERS, 0);
    assert!(!result, "corrupted proof should fail verification");
}

// ---------------------------------------------------------------------------
// vdf.txt stress-test vectors from chiavdf (1024-bit discriminant, depth 0..7)
// ---------------------------------------------------------------------------

const VDF_TXT: &str = include_str!("fixtures/vdf.txt");

struct VdfVec<'a> {
    challenge: &'a str,
    disc_bits: usize,
    input: &'a str,
    proof: &'a str,
    iters: u64,
    depth: u64,
}

fn parse_vdf_txt(content: &str) -> Vec<VdfVec<'_>> {
    let lines: Vec<&str> = content.lines().filter(|l| !l.is_empty()).collect();
    let mut out = Vec::new();
    for chunk in lines.chunks(6) {
        if chunk.len() < 6 {
            continue;
        }
        out.push(VdfVec {
            challenge: chunk[0],
            disc_bits: chunk[1].parse().unwrap(),
            input: chunk[2],
            proof: chunk[3],
            iters: chunk[4].parse().unwrap(),
            depth: chunk[5].parse().unwrap(),
        });
    }
    out
}

fn verify_vdf_vec(v: &VdfVec<'_>) -> bool {
    let challenge = hex_decode(v.challenge);
    let d = create_discriminant(&challenge, v.disc_bits);
    let input = hex_decode(v.input);
    let proof = hex_decode(v.proof);
    check_proof_of_time_n_wesolowski(&d, &input, &proof, v.iters, v.depth)
}

/// Fast smoke test: one depth=0 and one depth=2 vector from vdf.txt.
/// Exercises the 1024-bit discriminant path in ~35 ms (release) per vector.
#[test]
fn test_vdf_txt_sample() {
    let vecs = parse_vdf_txt(VDF_TXT);

    let d0 = vecs.iter().find(|v| v.depth == 0).expect("depth=0 vector");
    assert!(verify_vdf_vec(d0), "depth=0 vector failed");

    let d2 = vecs.iter().find(|v| v.depth == 2).expect("depth=2 vector");
    assert!(verify_vdf_vec(d2), "depth=2 vector failed");
}

/// Full vdf.txt test suite — all 110 vectors (depth 0..7, 1024-bit discriminant).
/// Skipped by default due to runtime (~15 s release / ~70 s debug).
/// Run with: cargo test --release -- --ignored test_vdf_txt_all
#[test]
#[ignore]
fn test_vdf_txt_all() {
    let vecs = parse_vdf_txt(VDF_TXT);
    let mut passed = 0;
    let mut failed = 0;

    for v in &vecs {
        if verify_vdf_vec(v) {
            passed += 1;
        } else {
            failed += 1;
            eprintln!(
                "FAIL depth={} iters={} challenge={}...",
                v.depth,
                v.iters,
                &v.challenge[..12]
            );
        }
    }

    assert_eq!(failed, 0, "{}/{} vectors failed", failed, passed + failed);
}
